func TestCompactDiffFormatter_Format_MultipleActions(t *testing.T) {
	f := &CompactDiffFormatter{}
	addrCreate := mustParseResourceInstanceAddr("aws_instance.create_me")
	addrUpdate := mustParseResourceInstanceAddr("aws_instance.update_me")
	addrDelete := mustParseResourceInstanceAddr("aws_instance.delete_me")

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr:      addrCreate,
					ChangeSrc: plans.ChangeSrc{Action: plans.Create},
				},
				{
					Addr:      addrUpdate,
					ChangeSrc: plans.ChangeSrc{Action: plans.Update},
				},
				{
					Addr:      addrDelete,
					ChangeSrc: plans.ChangeSrc{Action: plans.Delete},
				},
			},
		},
	}

	result := f.Format(plan, nil)

	if !strings.Contains(result, "[create] aws_instance.create_me") {
		t.Errorf("expected create line in output, got:\n%s", result)
	}
	if !strings.Contains(result, "[update] aws_instance.update_me") {
		t.Errorf("expected update line in output, got:\n%s", result)
	}
	if !strings.Contains(result, "[delete] aws_instance.delete_me") {
		t.Errorf("expected delete line in output, got:\n%s", result)
	}
	if !strings.Contains(result, "Plan:") {
		t.Errorf("expected 'Plan:' summary in output, got:\n%s", result)
	}
	if !strings.Contains(result, "1 to create") {
		t.Errorf("expected '1 to create' in summary, got:\n%s", result)
	}
	if !strings.Contains(result, "1 to update") {
		t.Errorf("expected '1 to update' in summary, got:\n%s", result)
	}
	if !strings.Contains(result, "1 to delete") {
		t.Errorf("expected '1 to delete' in summary, got:\n%s", result)
	}

	// Create should appear before update, which should appear before delete
	createIdx := strings.Index(result, "[create]")
	updateIdx := strings.Index(result, "[update]")
	deleteIdx := strings.Index(result, "[delete]")
	if createIdx > updateIdx || updateIdx > deleteIdx {
		t.Errorf("expected create before update before delete, got:\n%s", result)
	}
}

func TestCompactDiffFormatter_Format_GroupedByAction(t *testing.T) {
	f := &CompactDiffFormatter{}
	addr1 := mustParseResourceInstanceAddr("aws_instance.first")
	addr2 := mustParseResourceInstanceAddr("aws_instance.second")

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr:      addr1,
					ChangeSrc: plans.ChangeSrc{Action: plans.Create},
				},
				{
					Addr:      addr2,
					ChangeSrc: plans.ChangeSrc{Action: plans.Create},
				},
			},
		},
	}

	result := f.Format(plan, nil)

	if !strings.Contains(result, "2 to create") {
		t.Errorf("expected '2 to create' in summary, got:\n%s", result)
	}
}

